ALTER TABLE educations ADD COLUMN IF NOT EXISTS program_summary TEXT;
ALTER TABLE educations ADD COLUMN IF NOT EXISTS program_distribution TEXT;

ALTER TABLE courses ADD COLUMN IF NOT EXISTS formation_year VARCHAR(80);
ALTER TABLE courses ADD COLUMN IF NOT EXISTS semester VARCHAR(80);
ALTER TABLE courses ADD COLUMN IF NOT EXISTS hours VARCHAR(80);
ALTER TABLE courses ADD COLUMN IF NOT EXISTS ects VARCHAR(160);

ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    skills_summary = EXCLUDED.skills_summary,
    display_order = EXCLUDED.display_order,
    updated_at = now();

WITH category AS (SELECT id FROM course_categories WHERE name = 'Sciences pour l’ingénieur')
ON CONFLICT (code) DO UPDATE SET title=EXCLUDED.title, formation_year=EXCLUDED.formation_year, semester=EXCLUDED.semester, hours=EXCLUDED.hours, ects=EXCLUDED.ects, description=EXCLUDED.description, skills_summary=EXCLUDED.skills_summary, category_id=EXCLUDED.category_id, display_order=EXCLUDED.display_order, updated_at=now();

