WITH esiee_educations AS (
    SELECT e.id
    FROM educations e
    LEFT JOIN schools s ON s.id = e.school_id
    WHERE lower(COALESCE(s.name, '')) LIKE '%esiee%'
),
esiee_courses AS (
    SELECT id FROM courses WHERE code LIKE 'ESIEE\_%' ESCAPE '\'
)
SELECT esiee_educations.id, esiee_courses.id
FROM esiee_educations
CROSS JOIN esiee_courses
ON CONFLICT DO NOTHING;

UPDATE educations
SET context = COALESCE(NULLIF(context, ''), 'Cette formation d’ingénieur en systèmes embarqués s’inscrit dans mon objectif de devenir ingénieur capable de concevoir, développer, intégrer et valider des systèmes électroniques et logiciels embarqués. Elle relie les sciences de l’ingénieur, l’électronique, le logiciel embarqué, le temps réel, les capteurs, les réseaux de terrain, la sécurité et l’expérience en entreprise.'),
    program_summary = COALESCE(NULLIF(program_summary, ''), 'La formation d’ingénieur en systèmes embarqués à ESIEE Paris combine des enseignements scientifiques, électroniques, informatiques et professionnels. Le programme associe cours, travaux dirigés, travaux pratiques, projets multidisciplinaires et missions en entreprise. Il permet de développer des compétences en électronique embarquée, microcontrôleurs, logiciel embarqué, temps réel, capteurs, systèmes physiques, réseaux de terrain, sécurité, validation, innovation et management de projet.'),
    program_distribution = COALESCE(NULLIF(program_distribution, ''), 'Ingénierie embarquée, transitions, R&D : 22,5%
Informatique & logiciels embarqués : 20,2%
Sciences humaines, anglais & management : 20,2%
Électronique, capteurs & systèmes physiques : 19,1%
Sciences de l’ingénieur, mathématiques et physique : 10,1%
Projet fil rouge : 7,9%')
WHERE id IN (
    SELECT e.id
    FROM educations e
    LEFT JOIN schools s ON s.id = e.school_id
    WHERE lower(COALESCE(s.name, '')) LIKE '%esiee%'
);

UPDATE educations
SET context = COALESCE(NULLIF(context, ''), 'La formation UTC renforce mon socle en informatique, mathématiques, systèmes, robotique et technologies avancées. Elle complète mon parcours GEII en élargissant mes compétences vers l’algorithmique, les bases de données, les réseaux, les systèmes d’exploitation, l’optimisation, la robotique, le temps réel et l’analyse critique du rôle de l’ingénieur.'),
    program_summary = COALESCE(NULLIF(program_summary, ''), 'Le programme suivi à l’UTC m’a permis de structurer un socle scientifique et informatique solide, avec des UV en algorithmique, programmation orientée objet, systèmes d’exploitation, bases de données, réseaux, systèmes temps réel, robotique, optimisation, anglais et sciences humaines.')
WHERE id IN (
    SELECT e.id
    FROM educations e
    LEFT JOIN schools s ON s.id = e.school_id
    WHERE lower(COALESCE(s.name, '')) LIKE '%utc%'
       OR lower(COALESCE(s.name, '')) LIKE '%technologie de compi%'
);
