INSERT INTO course_categories (name, description, skills_summary, display_order) VALUES
('Sciences pour l’ingénieur', 'Enseignements destinés à consolider les bases scientifiques nécessaires à la modélisation, l’optimisation, l’analyse statistique et la compréhension des systèmes d’ingénierie.', 'Mathématiques pour l’ingénieur, modélisation, optimisation, statistiques, probabilités, physique appliquée, systèmes de communication, analyse scientifique.', 201),
('Sciences et techniques pour les transitions', 'Enseignements centrés sur les enjeux environnementaux, numériques et énergétiques, avec une approche orientée transition écologique, sobriété, écoconception et technologies durables.', 'Écoconception, analyse du cycle de vie, environnement numérique, transition énergétique, développement durable, IA, cybersécurité, traitement de données, mesure environnementale.', 202),
('Projet multidisciplinaire et fil rouge', 'Enseignements et projets permettant de mettre en pratique les compétences techniques à travers des réalisations progressives, multidisciplinaires et professionnalisantes.', 'Microcontrôleurs, développement embarqué, projet fil rouge, IHM, Android, LabVIEW, ingénierie dirigée par les modèles, propriété intellectuelle, travail en équipe, gestion de projet.', 203),
('Architectures, électroniques et systèmes embarqués', 'Enseignements centrés sur l’électronique analogique et numérique, les capteurs, les architectures embarquées, les systèmes asservis, les microprocesseurs, l’électronique de commande et la compatibilité électromagnétique.', 'Électronique analogique, électronique numérique, capteurs, conditionnement de signal, architectures numériques, microprocesseurs, HIL, systèmes asservis, CEM, moteurs électriques, électronique de commande.', 204),
('Informatique, logiciels embarqués et IA', 'Enseignements centrés sur la programmation, les logiciels embarqués, les systèmes critiques, le temps réel, l’intelligence artificielle embarquée, la vision et le traitement d’images.', 'Logiciel embarqué, systèmes temps réel, logiciels critiques, IA embarquée, vision embarquée, traitement d’images, Android, algorithmique, programmation, validation logicielle.', 205),
('Réseaux, sécurité et fiabilité des systèmes embarqués', 'Enseignements centrés sur les réseaux, la sécurité, la cryptographie, la validation, les méthodes formelles et la qualification des systèmes embarqués.', 'Réseaux de terrain, cybersécurité, cryptographie, sécurité embarquée, méthodes formelles, validation, qualification système, sûreté de fonctionnement.', 206),
('Technologies des systèmes embarqués', 'Enseignements liés aux technologies matérielles, procédés intégrés, communication sans fil, modélisation industrielle et analyse des marchés des systèmes embarqués.', 'Technologies intégrées, salle blanche, communication sans fil, modélisation de systèmes électroniques industriels, produits et marchés, R&D, systèmes embarqués industriels.', 207),
('Anglais, management et sciences humaines', 'Enseignements liés à l’anglais, à la communication professionnelle, au management, à l’innovation, au droit, aux sciences humaines, à la RSE et à la compréhension de l’entreprise.', 'Anglais technique, communication professionnelle, management de projet, innovation, stratégie, négociation, droit, finances, RSE, management interculturel.', 208),
('Séquence professionnelle et alternance', 'Périodes en entreprise permettant d’appliquer les compétences acquises à l’école, de développer une posture professionnelle et de progresser sur des missions techniques réelles.', 'Alternance, expérience professionnelle, autonomie, mission technique, rapport professionnel, soutenance, tutorat, analyse de situation, compétences métier.', 209)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
('ESIEE_SCI_01', 'Outils mathématiques pour la modélisation', '1re année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences pour l’ingénieur — 3 ECTS', 'Étude des outils mathématiques nécessaires à la modélisation de systèmes physiques, électroniques et informatiques dans un contexte d’ingénierie.', 'Mathématiques appliquées, modélisation, analyse de systèmes, calcul scientifique.', (SELECT id FROM category), 1),
('ESIEE_SCI_02', 'Fondamentaux de mathématiques pour l’ingénieur 1', '1re année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences pour l’ingénieur — 3 ECTS', 'Renforcement des fondamentaux mathématiques nécessaires à l’analyse, au raisonnement scientifique et à la résolution de problèmes d’ingénierie.', 'Mathématiques pour l’ingénieur, raisonnement scientifique, calcul, résolution de problèmes.', (SELECT id FROM category), 2),
('ESIEE_SCI_03', 'Méthodes d’optimisation', '1re année', 'Semestre 2', '30 h', 'Inclus dans le bloc Sciences pour l’ingénieur — 3 ECTS', 'Introduction aux méthodes d’optimisation utilisées pour formuler, analyser et résoudre des problèmes techniques ou industriels.', 'Optimisation, modélisation, résolution de problèmes, méthodes numériques.', (SELECT id FROM category), 3),
('ESIEE_SCI_04', 'Fondamentaux de mathématiques pour l’ingénieur 2', '1re année', 'Semestre 2', '30 h', 'Inclus dans le bloc Sciences pour l’ingénieur — 3 ECTS', 'Approfondissement des notions mathématiques utiles à la modélisation, à l’analyse de systèmes et à la résolution de problèmes scientifiques.', 'Mathématiques appliquées, modélisation, analyse, calcul scientifique.', (SELECT id FROM category), 4),
('ESIEE_SCI_05', 'Statistiques et probabilités', '2e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences pour l’ingénieur — 3 ECTS', 'Étude des probabilités et statistiques appliquées à l’analyse de données, à l’incertitude, à la modélisation et à la prise de décision en ingénierie.', 'Statistiques, probabilités, analyse de données, incertitude, modélisation.', (SELECT id FROM category), 5),
('ESIEE_SCI_06', 'Fondements des systèmes de communication', '2e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences pour l’ingénieur — 3 ECTS', 'Introduction aux principes scientifiques et techniques des systèmes de communication utilisés dans les systèmes électroniques et numériques.', 'Systèmes de communication, signal, transmission, réseaux, communication numérique.', (SELECT id FROM category), 6)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
('ESIEE_TR_01', 'Écoconception et analyse du cycle de vie', '1re année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences et techniques pour la transition — 3 ECTS', 'Étude des principes d’écoconception et d’analyse du cycle de vie afin d’évaluer l’impact environnemental d’un produit ou d’un système technique.', 'Écoconception, analyse du cycle de vie, développement durable, impact environnemental, conception responsable.', (SELECT id FROM category), 1),
('ESIEE_TR_02', 'Environnement numérique de l’ingénieur', '1re année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences et techniques pour la transition — 3 ECTS', 'Découverte de l’environnement numérique de travail de l’ingénieur, des outils numériques et des méthodes utilisées pour concevoir, documenter, analyser et collaborer.', 'Outils numériques, environnement d’ingénierie, documentation, collaboration, méthodes de travail.', (SELECT id FROM category), 2),
('ESIEE_TR_03', 'Physique pour la transition énergétique', '1re année', 'Semestre 2', '30 h', 'Inclus dans le bloc Sciences et techniques pour la transition — 3 ECTS', 'Étude des principes physiques liés à l’énergie, aux systèmes énergétiques et aux enjeux de transition énergétique.', 'Physique appliquée, transition énergétique, énergie, systèmes physiques, modélisation.', (SELECT id FROM category), 3),
('ESIEE_TR_04', 'Algorithmique et programmation pour l’ingénieur', '1re année', 'Semestre 2', '30 h', 'Inclus dans le bloc Sciences et techniques pour la transition — 3 ECTS', 'Introduction à l’algorithmique et à la programmation appliquées aux problématiques d’ingénierie.', 'Algorithmique, programmation, résolution de problèmes, structuration du code, logique informatique.', (SELECT id FROM category), 4),
('ESIEE_TR_05', 'Introduction aux réseaux, à la sécurité et à la cybersécurité', '2e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences et techniques pour les transitions — 3 ECTS', 'Introduction aux réseaux informatiques, aux principes de sécurité numérique et aux enjeux de cybersécurité dans les systèmes connectés.', 'Réseaux, cybersécurité, sécurité informatique, protocoles, systèmes connectés.', (SELECT id FROM category), 5),
('ESIEE_TR_06', 'Traitement et analyse de données', '2e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences et techniques pour les transitions — 3 ECTS', 'Méthodes de collecte, traitement, analyse et interprétation de données dans un contexte scientifique et technique.', 'Analyse de données, traitement de données, statistiques appliquées, visualisation, interprétation.', (SELECT id FROM category), 6),
('ESIEE_TR_07', 'Dérèglement climatique et pollutions 1 : modèles, impacts', '2e année', 'Semestre 2', '30 h', 'Inclus dans le bloc Sciences et techniques pour les transitions — 3 ECTS', 'Étude des modèles, impacts et enjeux liés au dérèglement climatique et aux pollutions.', 'Développement durable, climat, modélisation, analyse d’impact, transition écologique.', (SELECT id FROM category), 7),
('ESIEE_TR_08', 'Introduction à l’IA', '2e année', 'Semestre 2', '30 h', 'Inclus dans le bloc Sciences et techniques pour les transitions — 3 ECTS', 'Introduction aux concepts fondamentaux de l’intelligence artificielle et à ses applications dans les systèmes numériques et industriels.', 'Intelligence artificielle, apprentissage automatique, analyse de données, algorithmique, modélisation.', (SELECT id FROM category), 8),
('ESIEE_TR_09', 'Du capteur au cloud : mesure pour l’environnement', '3e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences et techniques pour les transitions — 3 ECTS', 'Étude d’une chaîne complète de mesure environnementale, depuis l’acquisition par capteur jusqu’à la transmission et l’exploitation des données dans le cloud.', 'Capteurs, acquisition de données, objets connectés, cloud, mesure environnementale, traitement de données.', (SELECT id FROM category), 9),
('ESIEE_TR_10', 'Dérèglement climatique et pollutions 2 : atelier DD', '3e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sciences et techniques pour les transitions — 3 ECTS', 'Atelier de développement durable appliqué notamment aux transports et aux véhicules électriques, avec analyse des enjeux environnementaux et techniques.', 'Développement durable, RSE, véhicules électriques, analyse d’impact, transition énergétique.', (SELECT id FROM category), 10)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
('ESIEE_PRJ_01', 'Microcontrôleurs 1', '1re année', 'Semestre 1', '30 h', '2 ECTS', 'Première approche des microcontrôleurs, de leur programmation et de leur utilisation pour piloter des entrées/sorties et réaliser des fonctions embarquées simples.', 'Microcontrôleurs, C embarqué, GPIO, programmation bas niveau, électronique embarquée.', (SELECT id FROM category), 1),
('ESIEE_PRJ_02', 'Microcontrôleurs 2', '1re année', 'Semestre 2', '30 h', '2 ECTS', 'Approfondissement de la programmation des microcontrôleurs et de l’intégration de fonctions embarquées plus avancées.', 'Microcontrôleurs, timers, interruptions, ADC, PWM, programmation embarquée, intégration matérielle/logicielle.', (SELECT id FROM category), 2),
('ESIEE_PRJ_03', 'IHM / Android', '2e année', 'Semestre 1', '20 h', 'Inclus dans le bloc Projet multidisciplinaire — 2 ECTS', 'Conception d’interfaces homme-machine et développement d’applications Android dans le cadre de projets techniques.', 'IHM, Android, interface utilisateur, développement mobile, ergonomie.', (SELECT id FROM category), 3),
('ESIEE_PRJ_04', 'Atelier LabVIEW', '2e année', 'Semestre 1', '10 h', 'Inclus dans le bloc Projet multidisciplinaire — 2 ECTS', 'Utilisation de LabVIEW pour l’acquisition de données, la mesure, l’automatisation ou le pilotage de systèmes.', 'LabVIEW, acquisition de données, instrumentation, automatisation, mesure.', (SELECT id FROM category), 4),
('ESIEE_PRJ_05', 'Ingénierie dirigée par les modèles', '2e année', 'Semestre 2', '30 h', '2 ECTS', 'Introduction à l’ingénierie dirigée par les modèles pour concevoir, structurer et générer des systèmes logiciels ou techniques à partir de modèles abstraits.', 'Modélisation, ingénierie dirigée par les modèles, architecture logicielle, conception système.', (SELECT id FROM category), 5),
('ESIEE_PRJ_06', 'Fil rouge', '3e année', 'Semestre 1', '125 h', 'Inclus dans le bloc Projet multidisciplinaire — 8 ECTS', 'Projet long permettant de mobiliser les compétences acquises en électronique, logiciel embarqué, systèmes physiques, management de projet et validation autour d’une réalisation technique complète.', 'Projet d’ingénierie, systèmes embarqués, conception, intégration, validation, travail en équipe, documentation technique.', (SELECT id FROM category), 6),
('ESIEE_PRJ_07', 'Brevet / Propriété intellectuelle', '3e année', 'Semestre 1', '15 h', 'Inclus dans le bloc Projet multidisciplinaire — 8 ECTS', 'Introduction aux notions de propriété intellectuelle, brevet, protection de l’innovation et valorisation technique.', 'Propriété intellectuelle, brevet, innovation, protection technique, valorisation.', (SELECT id FROM category), 7)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
('ESIEE_ARCH_01', 'Électronique numérique', '1re année', 'Semestre 1', '24 h', 'Inclus dans le bloc Architectures & Électroniques embarquées — 4 ECTS', 'Étude des circuits logiques, des architectures numériques et des principes de conception électronique numérique.', 'Électronique numérique, logique combinatoire, logique séquentielle, architectures numériques, circuits logiques.', (SELECT id FROM category), 1),
('ESIEE_ARCH_02', 'Électronique analogique', '1re année', 'Semestre 1', '28 h', 'Inclus dans le bloc Architectures & Électroniques embarquées — 4 ECTS', 'Étude des circuits analogiques, du conditionnement de signal, des composants électroniques et des fonctions d’acquisition.', 'Électronique analogique, composants électroniques, conditionnement de signal, mesures, acquisition.', (SELECT id FROM category), 2),
('ESIEE_ARCH_03', 'Systèmes asservis, HIL', '1re année', 'Semestre 1', '28 h', 'Inclus dans le bloc Architectures & Électroniques embarquées — 4 ECTS', 'Étude des systèmes asservis et introduction aux approches Hardware-in-the-Loop pour tester et valider des systèmes commandés.', 'Systèmes asservis, HIL, automatique, validation, commande, tests.', (SELECT id FROM category), 3),
('ESIEE_ARCH_04', 'Capteurs et électronique de conditionnement', '1re année', 'Semestre 2', '28 h', 'Inclus dans le bloc Architectures & Électroniques embarquées — 4 ECTS', 'Étude des capteurs et des circuits de conditionnement permettant d’adapter les signaux mesurés à une chaîne d’acquisition.', 'Capteurs, conditionnement de signal, électronique analogique, acquisition, mesures physiques.', (SELECT id FROM category), 4),
('ESIEE_ARCH_05', 'Architectures numériques', '1re année', 'Semestre 2', '24 h', 'Inclus dans le bloc Architectures & Électroniques embarquées — 4 ECTS', 'Étude des architectures numériques utilisées dans les systèmes embarqués et électroniques.', 'Architectures numériques, logique numérique, systèmes embarqués, architecture matérielle.', (SELECT id FROM category), 5),
('ESIEE_ARCH_06', 'Physique appliquée', '1re année', 'Semestre 2', '28 h', 'Inclus dans le bloc Architectures & Électroniques embarquées — 4 ECTS', 'Application des principes physiques aux systèmes électroniques, capteurs, mesures et systèmes embarqués.', 'Physique appliquée, systèmes physiques, mesures, modélisation, électronique.', (SELECT id FROM category), 6),
('ESIEE_ARCH_07', 'Systèmes asservis, HIL', '2e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Électroniques embarqués avancées — 4 ECTS', 'Approfondissement des systèmes asservis et des méthodes de validation Hardware-in-the-Loop pour systèmes embarqués.', 'Systèmes asservis, HIL, validation système, commande, modélisation.', (SELECT id FROM category), 7),
('ESIEE_ARCH_08', 'Microprocesseur avancé', '2e année', 'Semestre 1', '20 h', 'Inclus dans le bloc Électroniques embarqués avancées — 4 ECTS', 'Étude avancée des microprocesseurs, de leur architecture et de leur intégration dans les systèmes embarqués.', 'Microprocesseurs, architecture processeur, systèmes embarqués, programmation bas niveau.', (SELECT id FROM category), 8),
('ESIEE_ARCH_09', 'Compatibilité électromagnétique', '2e année', 'Semestre 1', '20 h', 'Inclus dans le bloc Électroniques embarqués avancées — 4 ECTS', 'Étude des perturbations électromagnétiques, de leur propagation, de leur impact sur les systèmes électroniques et des règles de conception associées.', 'CEM, compatibilité électromagnétique, perturbations, intégrité du signal, conception électronique.', (SELECT id FROM category), 9),
('ESIEE_ARCH_10', 'Moteurs électriques et électroniques de commande', '2e année', 'Semestre 2', '30 h', 'Inclus dans le bloc Ingénierie des systèmes embarqués — 5 ECTS', 'Étude des moteurs électriques, de leur commande et des circuits électroniques associés à la conversion et au pilotage d’énergie.', 'Moteurs électriques, électronique de commande, PWM, électronique de puissance, conversion d’énergie.', (SELECT id FROM category), 10)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
('ESIEE_SW_01', 'Système temps réel', '2e année', 'Semestre 2', '28 h', 'Inclus dans le bloc Ingénierie des systèmes embarqués — 5 ECTS', 'Étude des systèmes soumis à des contraintes temporelles, avec notions d’ordonnancement, tâches, interruptions, synchronisation et déterminisme.', 'Temps réel, RTOS, ordonnancement, tâches, interruptions, synchronisation, déterminisme.', (SELECT id FROM category), 1),
