('ESIEE_SW_03', 'Particularités des transports aéronautiques, guidés et automobiles', '3e année', 'Semestre 1', '24 h', 'Inclus dans le bloc Logiciels embarqués — 5 ECTS', 'Étude des contraintes propres aux systèmes embarqués utilisés dans les transports aéronautiques, guidés et automobiles.', 'Systèmes embarqués critiques, transport, contraintes industrielles, sûreté de fonctionnement, validation.', (SELECT id FROM category), 3),
('ESIEE_SW_04', 'Logiciels critiques temps réel embarqué', '3e année', 'Semestre 1', '24 h', 'Inclus dans le bloc Logiciels embarqués — 5 ECTS', 'Développement et validation de logiciels embarqués soumis à des contraintes temps réel et de criticité.', 'Logiciels critiques, temps réel embarqué, validation logicielle, sûreté, programmation embarquée.', (SELECT id FROM category), 4),
('ESIEE_SW_05', 'IA embarquée', '3e année', 'Semestre 1', '22 h', 'Inclus dans le bloc Logiciels embarqués — 5 ECTS', 'Étude des méthodes d’intelligence artificielle adaptées aux systèmes embarqués et aux contraintes de ressources.', 'IA embarquée, machine learning embarqué, optimisation, contraintes mémoire, traitement embarqué.', (SELECT id FROM category), 5),
('ESIEE_SW_06', 'Vision, traitement d’images embarquées', '3e année', 'Semestre 1', '25 h', 'Inclus dans le bloc Logiciels embarqués — 5 ECTS', 'Étude des méthodes de vision et de traitement d’images intégrées dans des systèmes embarqués.', 'Vision embarquée, traitement d’images, acquisition, filtrage, analyse d’images, systèmes embarqués.', (SELECT id FROM category), 6)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
