('ESIEE_SEC_03', 'Sécurité des applications embarquées', '3e année', 'Semestre 1', '24 h', 'Inclus dans le bloc Sécurité et fiabilité des systèmes embarqués — 5 ECTS', 'Étude des vulnérabilités, menaces et méthodes de sécurisation propres aux applications embarquées.', 'Sécurité embarquée, cybersécurité, applications embarquées, analyse de vulnérabilités, protection système.', (SELECT id FROM category), 3),
('ESIEE_SEC_04', 'Méthodes formelles', '3e année', 'Semestre 1', '24 h', 'Inclus dans le bloc Sécurité et fiabilité des systèmes embarqués — 5 ECTS', 'Introduction aux méthodes formelles permettant de spécifier, vérifier et valider rigoureusement le comportement de systèmes critiques.', 'Méthodes formelles, vérification, validation, spécification, systèmes critiques.', (SELECT id FROM category), 4),
('ESIEE_SEC_05', 'Validation et qualification système', '3e année', 'Semestre 1', '30 h', 'Inclus dans le bloc Sécurité et fiabilité des systèmes embarqués — 5 ECTS', 'Étude des méthodes de validation, qualification et vérification de systèmes embarqués dans un contexte industriel.', 'Validation système, qualification, tests, vérification, sûreté de fonctionnement, documentation technique.', (SELECT id FROM category), 5)
INSERT INTO courses (code, title, formation_year, semester, hours, ects, description, skills_summary, category_id, display_order) VALUES
